    func loadPortfolio() {
        guard let session else { return }
        portfolioService.fetchPortfolio(token: session.authToken)
            .receive(on: DispatchQueue.main)
            .sink(receiveCompletion: { _ in }, receiveValue: { [weak self] portfolio in
                self?.portfolio = portfolio
            })
            .store(in: &cancellables)
