struct Portfolio {
    var cashBalance: Double
    var totalValue: Double
    var dayProfitLoss: Double
    var positions: [Position]
    
    mutating func refreshMarketValue(using quote: StockQuote) {
        guard let index = positions.firstIndex(where: { $0.symbol == quote.symbol }) else { return }
        positions[index].currentPrice = quote.price
        totalValue = cashBalance + positions.reduce(0) { $0 + $1.marketValue }
    }
    
