enum TradingError: LocalizedError {
    case unauthorized
    case invalidURL
    case invalidOrder
    case network
    case decoding
    
    var errorDescription: String? {
        switch self {
        case .unauthorized: return "Authentication required."
        case .invalidURL: return "Invalid trading endpoint."
        case .invalidOrder: return "Please review order details."
        case .network: return "Network error while executing trade."
        case .decoding: return "Unable to parse server response."
        }
    }
}

final class TradingService {
    private let client = APIClient.shared
    
    func execute(request: OrderRequest, token: String) -> AnyPublisher<TradeOrder, Error> {
        guard !request.symbol.isEmpty, request.quantity > 0 else {
            return Fail(error: TradingError.invalidOrder).eraseToAnyPublisher()
        }
        
        let endpoint = "/v1/trades/execute"
        return client.perform(
            endpoint: endpoint,
            method: "POST",
            token: token,
            body: request
        )
        .map { (_: EmptyResponse) in
            TradeOrder(
                id: UUID().uuidString,
                symbol: request.symbol,
                side: request.side,
                quantity: request.quantity,
                orderType: request.orderType,
                status: .filled,
                executedPrice: request.limitPrice ?? Double.random(in: 100...900),
                timestamp: Date()
            )
        }
        .eraseToAnyPublisher()
    }
}

