final class MarketDataService {
    let quoteStream = PassthroughSubject<StockQuote, Never>()
    private var timer: AnyCancellable?
    private let symbols = StockQuote.mock
    
    func connect() {
        timer?.cancel()
        timer = Timer.publish(every: 1.2, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                guard let self else { return }
                for quote in self.symbols {
                    let updated = StockQuote(
                        symbol: quote.symbol,
                        companyName: quote.companyName,
                        price: max(1, quote.price + Double.random(in: -2.0...2.0)),
                        changePercent: Double.random(in: -3.5...3.5)
                    )
                    self.quoteStream.send(updated)
                }
            }
    }
}

struct EmptyResponse: Codable {}

final class APIClient {
    static let shared = APIClient()
    private let baseURL = URL(string: "https://api.investment-platform.com")!
    private let session: URLSession
    
    private init() {
        let config = URLSessionConfiguration.ephemeral
        config.waitsForConnectivity = true
        config.timeoutIntervalForRequest = 15
        config.timeoutIntervalForResource = 30
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        self.session = URLSession(configuration: config)
    }
    
    func perform<T: Decodable, U: Encodable>(endpoint: String, method: String, token: String, body: U?) -> AnyPublisher<T, Error> {
        guard let url = URL(string: endpoint, relativeTo: baseURL) else {
            return Fail(error: TradingError.invalidURL).eraseToAnyPublisher()
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        request.setValue(SecurityHeaders.timestamp, forHTTPHeaderField: "X-Timestamp")
        request.setValue(SecurityHeaders.nonce, forHTTPHeaderField: "X-Nonce")
        request.setValue(SecurityHeaders.signature(token: token, endpoint: endpoint, method: method), forHTTPHeaderField: "X-Signature")
        
        if let body {
            request.httpBody = try? JSONEncoder().encode(body)
        }
        
        return session.dataTaskPublisher(for: request)
            .tryMap { data, response in
                guard let http = response as? HTTPURLResponse, 200..<300 ~= http.statusCode else {
                    throw TradingError.network
                }
                return data.isEmpty ? Data("{}".utf8) : data
            }
            .decode(type: T.self, decoder: JSONDecoder())
            .eraseToAnyPublisher()
    }
}

enum SecurityHeaders {
    static var timestamp: String {
        String(Int(Date().timeIntervalSince1970))
    }
    
    static var nonce: String {
        UUID().uuidString.replacingOccurrences(of: "-", with: "")
    }
    
    static func signature(token: String, endpoint: String, method: String) -> String {
        let payload = "\(method)|\(endpoint)|\(timestamp)|\(nonce)|\(token)"
        let key = SymmetricKey(data: Data(token.utf8))
        let mac = HMAC<SHA256>.authenticationCode(for: Data(payload.utf8), using: key)
        return Data(mac).base64EncodedString()
    }
}

enum TokenSigner {
    static func sign(apiKey: String, secret: String) -> String {
        let key = SymmetricKey(data: Data(secret.utf8))
        let mac = HMAC<SHA256>.authenticationCode(for: Data(apiKey.utf8), using: key)
        return Data(mac).base64EncodedString()
    }
}

final class SecureTokenStore {
    private let service = "com.rapidtrade.auth"
    private let account = "broker_token"
    
    func saveToken(_ token: String) {
        deleteToken()
        guard let data = token.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemAdd(query as CFDictionary, nil)
    }
    
    func loadToken() -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var item: CFTypeRef?
        SecItemCopyMatching(query as CFDictionary, &item)
        guard let data = item as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func deleteToken() {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        SecItemDelete(query as CFDictionary)
    }
}

extension Double {
    var currency: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSNumber(value: self)) ?? "$0.00"
    }
    
    var signedCurrency: String {
        let sign = self >= 0 ? "+" : ""
        return "\(sign)\(currency)"
    }
    
    var signedPercent: String {
        let sign = self >= 0 ? "+" : ""
        return "\(sign)\(String(format: "%.2f", self))%"
    }
}